  /// (user) Withdraw from a Drift spot market through a marginfi account
  /// * amount - in the underlying token (e.g., USDC), in native decimals
  /// * withdraw_all - if true, withdraws entire position
  ///
  /// @param amount: u64
  /// @param withdrawAll: Option<bool>
  public static Instruction driftWithdraw(final AccountMeta invokedMarginfiProgramMeta,
                                          final List<AccountMeta> keys,
                                          final long amount,
                                          final Boolean withdrawAll) {
    final byte[] _data = new byte[
    16
    + (withdrawAll == null ? 1 : 2)
    ];
    int i = DRIFT_WITHDRAW_DISCRIMINATOR.write(_data, 0);
    putInt64LE(_data, i, amount);
    i += 8;
    SerDeUtil.writeOptional(1, withdrawAll, _data, i);

    return Instruction.createInstruction(invokedMarginfiProgramMeta, keys, _data);
  }

  /// @param amount: u64
  /// @param withdrawAll: Option<bool>
  public record DriftWithdrawIxData(Discriminator discriminator, long amount, Boolean withdrawAll) implements SerDe {  

    public static DriftWithdrawIxData read(final Instruction instruction) {
      return read(instruction.data(), instruction.offset());
    }

    public static final int AMOUNT_OFFSET = 8;
    public static final int WITHDRAW_ALL_OFFSET = 17;

    public static DriftWithdrawIxData read(final byte[] _data, final int _offset) {
      if (_data == null || _data.length == 0) {
        return null;
      }
      final var discriminator = createAnchorDiscriminator(_data, _offset);
      int i = _offset + discriminator.length();
      final var amount = getInt64LE(_data, i);
      i += 8;
      final Boolean withdrawAll;
      if (SerDeUtil.isAbsent(1, _data, i)) {
        withdrawAll = null;
      } else {
        ++i;
        withdrawAll = _data[i] == 1;
      }
      return new DriftWithdrawIxData(discriminator, amount, withdrawAll);
    }

    @Override
    public int write(final byte[] _data, final int _offset) {
      int i = _offset + discriminator.write(_data, _offset);
      putInt64LE(_data, i, amount);
      i += 8;
      i += SerDeUtil.writeOptional(1, withdrawAll, _data, i);
      return i - _offset;
    }

    @Override
    public int l() {
      return 8 + 8 + (withdrawAll == null ? 1 : (1 + 1));
    }
  }

